def transition(state, action):
    s = dict(state)
    name = action["name"]
    params = action.get("params") or {}

    bids = dict(s.get("bids", {}))
    allocations = dict(s.get("allocations", {}))
    offered = int(s.get("shares_offered", 0))

    if name == "bid":
        # Record/update a bidder's order. Any change to demand reopens the book,
        # so a stale allocation is cleared and must be recomputed.
        bidder = params.get("bidder")
        shares = params.get("shares", 0)
        if bidder is not None and isinstance(shares, (int, float)) and shares > 0:
            bids[bidder] = int(shares)
            allocations = {}
            s["status"] = "open"

    elif name == "allocate":
        # Fill the book. Undersubscribed -> everyone filled in full.
        # Oversubscribed -> pro-rata by floor(req * offered / demand).
        demand = sum(int(v) for v in bids.values())
        allocations = {}
        if demand > 0:
            if demand <= offered:
                for b, req in bids.items():
                    allocations[b] = int(req)
            else:
                for b, req in bids.items():
                    allocations[b] = int(int(req) * offered // demand)
            s["status"] = "allocated"

    elif name == "scale_back":
        # Reduce a named bidder's allocation, returning shares to the pool.
        bidder = params.get("bidder")
        shares = params.get("shares", 0)
        if bidder in allocations and isinstance(shares, (int, float)) and shares > 0:
            allocations[bidder] = max(0, int(allocations[bidder]) - int(shares))
            s["status"] = "scaled_back"

    total_demand = sum(int(v) for v in bids.values())
    total_allocated = sum(int(v) for v in allocations.values())
    s["bids"] = bids
    s["allocations"] = allocations
    s["total_demand"] = total_demand
    s["total_allocated"] = total_allocated
    s["available"] = offered - total_allocated
    s["oversubscription"] = round(total_demand / offered, 4) if offered else 0.0
    return s

