def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' in line:
            k, v = line.split(':', 1)
            k = k.strip().lower()
            v = v.strip()
            if k in ('shares_offered', 'offered', 'size'):
                if v.lstrip('-').isdigit():
                    out['shares_offered'] = int(v)
    return out
